import React from 'react';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend,
  BarElement,
  ArcElement,
} from 'chart.js';
import { Line, Bar, Doughnut } from 'react-chartjs-2';

// Register Chart.js components
ChartJS.register(
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  BarElement,
  ArcElement,
  Title,
  Tooltip,
  Legend
);

/**
 * Price Chart Component
 * Displays price history as a line chart
 */
interface PriceChartProps {
  data: { timestamp: number; price: number }[];
  symbol: string;
  timeframe: string;
  className?: string;
}

export const PriceChart: React.FC<PriceChartProps> = ({ 
  data, 
  symbol, 
  timeframe, 
  className = '' 
}) => {
  const chartData = {
    labels: data.map(item => {
      const date = new Date(item.timestamp);
      if (timeframe === '1h') {
        return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
      } else if (timeframe === '24h') {
        return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
      } else {
        return date.toLocaleDateString([], { month: 'short', day: 'numeric' });
      }
    }),
    datasets: [
      {
        label: `${symbol} Price`,
        data: data.map(item => item.price),
        borderColor: 'rgb(34, 197, 94)',
        backgroundColor: 'rgba(34, 197, 94, 0.1)',
        borderWidth: 2,
        fill: true,
        tension: 0.1,
        pointRadius: 0,
        pointHoverRadius: 6,
      },
    ],
  };

  const options = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: {
        display: false,
      },
      title: {
        display: false,
      },
      tooltip: {
        mode: 'index' as const,
        intersect: false,
        backgroundColor: 'rgba(15, 23, 42, 0.9)',
        titleColor: 'white',
        bodyColor: 'white',
        borderColor: 'rgba(71, 85, 105, 0.5)',
        borderWidth: 1,
        callbacks: {
          label: function(context: any) {
            return `${symbol}: $${context.parsed.y.toLocaleString(undefined, {
              minimumFractionDigits: 2,
              maximumFractionDigits: 2,
            })}`;
          },
        },
      },
    },
    scales: {
      x: {
        display: true,
        grid: {
          color: 'rgba(71, 85, 105, 0.3)',
        },
        ticks: {
          color: 'rgb(148, 163, 184)',
          maxTicksLimit: 8,
        },
      },
      y: {
        display: true,
        grid: {
          color: 'rgba(71, 85, 105, 0.3)',
        },
        ticks: {
          color: 'rgb(148, 163, 184)',
          callback: function(value: any) {
            return '$' + value.toLocaleString();
          },
        },
      },
    },
    interaction: {
      mode: 'index' as const,
      intersect: false,
    },
  };

  return (
    <div className={`${className}`}>
      <Line data={chartData} options={options} />
    </div>
  );
};

/**
 * Volume Chart Component
 * Displays trading volume as a bar chart
 */
interface VolumeChartProps {
  data: { timestamp: number; volume: number }[];
  symbol: string;
  className?: string;
}

export const VolumeChart: React.FC<VolumeChartProps> = ({ 
  data, 
  symbol, 
  className = '' 
}) => {
  const chartData = {
    labels: data.map(item => {
      const date = new Date(item.timestamp);
      return date.toLocaleDateString([], { month: 'short', day: 'numeric' });
    }),
    datasets: [
      {
        label: `${symbol} Volume`,
        data: data.map(item => item.volume),
        backgroundColor: 'rgba(59, 130, 246, 0.6)',
        borderColor: 'rgb(59, 130, 246)',
        borderWidth: 1,
      },
    ],
  };

  const options = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: {
        display: false,
      },
      tooltip: {
        backgroundColor: 'rgba(15, 23, 42, 0.9)',
        titleColor: 'white',
        bodyColor: 'white',
        borderColor: 'rgba(71, 85, 105, 0.5)',
        borderWidth: 1,
        callbacks: {
          label: function(context: any) {
            return `Volume: ${(context.parsed.y / 1000000).toFixed(2)}M`;
          },
        },
      },
    },
    scales: {
      x: {
        display: true,
        grid: {
          color: 'rgba(71, 85, 105, 0.3)',
        },
        ticks: {
          color: 'rgb(148, 163, 184)',
        },
      },
      y: {
        display: true,
        grid: {
          color: 'rgba(71, 85, 105, 0.3)',
        },
        ticks: {
          color: 'rgb(148, 163, 184)',
          callback: function(value: any) {
            return (value / 1000000).toFixed(0) + 'M';
          },
        },
      },
    },
  };

  return (
    <div className={`${className}`}>
      <Bar data={chartData} options={options} />
    </div>
  );
};

/**
 * Portfolio Allocation Chart
 * Displays portfolio allocation as a doughnut chart
 */
interface PortfolioChartProps {
  data: { symbol: string; value: number; percentage: number }[];
  className?: string;
}

export const PortfolioChart: React.FC<PortfolioChartProps> = ({ 
  data, 
  className = '' 
}) => {
  const colors = [
    'rgb(34, 197, 94)',   // Green
    'rgb(59, 130, 246)',  // Blue
    'rgb(245, 158, 11)',  // Yellow
    'rgb(239, 68, 68)',   // Red
    'rgb(168, 85, 247)',  // Purple
    'rgb(236, 72, 153)',  // Pink
    'rgb(14, 165, 233)',  // Sky
    'rgb(132, 204, 22)',  // Lime
  ];

  const chartData = {
    labels: data.map(item => item.symbol),
    datasets: [
      {
        data: data.map(item => item.percentage),
        backgroundColor: colors.slice(0, data.length),
        borderColor: colors.slice(0, data.length).map(color => color.replace('rgb', 'rgba').replace(')', ', 0.8)')),
        borderWidth: 2,
      },
    ],
  };

  const options = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: {
        position: 'right' as const,
        labels: {
          color: 'rgb(148, 163, 184)',
          usePointStyle: true,
          padding: 20,
          generateLabels: function(chart: any) {
            const dataset = chart.data.datasets[0];
            return chart.data.labels.map((label: string, i: number) => ({
              text: `${label} (${dataset.data[i].toFixed(1)}%)`,
              fillStyle: dataset.backgroundColor[i],
              strokeStyle: dataset.borderColor[i],
              lineWidth: dataset.borderWidth,
              pointStyle: 'circle',
              index: i,
            }));
          },
        },
      },
      tooltip: {
        backgroundColor: 'rgba(15, 23, 42, 0.9)',
        titleColor: 'white',
        bodyColor: 'white',
        borderColor: 'rgba(71, 85, 105, 0.5)',
        borderWidth: 1,
        callbacks: {
          label: function(context: any) {
            const item = data[context.dataIndex];
            return [
              `${item.symbol}: ${item.percentage.toFixed(1)}%`,
              `Value: $${item.value.toLocaleString(undefined, {
                minimumFractionDigits: 2,
                maximumFractionDigits: 2,
              })}`
            ];
          },
        },
      },
    },
    cutout: '60%',
  };

  return (
    <div className={`${className}`}>
      <Doughnut data={chartData} options={options} />
    </div>
  );
};

/**
 * Market Overview Chart
 * Displays top cryptocurrencies by market cap
 */
interface MarketOverviewChartProps {
  data: { symbol: string; marketCap: number; change24h: number }[];
  className?: string;
}

export const MarketOverviewChart: React.FC<MarketOverviewChartProps> = ({ 
  data, 
  className = '' 
}) => {
  const formatMarketCap = (value: number) => {
    if (value >= 1e12) {
      return `$${(value / 1e12).toFixed(2)}T`;
    } else if (value >= 1e9) {
      return `$${(value / 1e9).toFixed(2)}B`;
    } else if (value >= 1e6) {
      return `$${(value / 1e6).toFixed(2)}M`;
    } else {
      return `$${value.toLocaleString()}`;
    }
  };

  const chartData = {
    labels: data.map(item => item.symbol),
    datasets: [
      {
        label: 'Market Cap',
        data: data.map(item => item.marketCap / 1000000000), // Convert to billions for consistent display
        backgroundColor: data.map(item => 
          item.change24h >= 0 ? 'rgba(34, 197, 94, 0.6)' : 'rgba(239, 68, 68, 0.6)'
        ),
        borderColor: data.map(item => 
          item.change24h >= 0 ? 'rgb(34, 197, 94)' : 'rgb(239, 68, 68)'
        ),
        borderWidth: 1,
      },
    ],
  };

  const options = {
    responsive: true,
    maintainAspectRatio: false,
    animation: {
      duration: 0, // Remove animations for stable display
    },
    plugins: {
      legend: {
        display: false,
      },
      tooltip: {
        backgroundColor: 'rgba(15, 23, 42, 0.9)',
        titleColor: 'white',
        bodyColor: 'white',
        borderColor: 'rgba(71, 85, 105, 0.5)',
        borderWidth: 1,
        callbacks: {
          label: function(context: any) {
            const item = data[context.dataIndex];
            return [
              `Market Cap: ${formatMarketCap(item.marketCap)}`,
              `24h Change: ${item.change24h >= 0 ? '+' : ''}${item.change24h.toFixed(2)}%`
            ];
          },
        },
      },
    },
    scales: {
      x: {
        display: true,
        grid: {
          color: 'rgba(71, 85, 105, 0.3)',
        },
        ticks: {
          color: 'rgb(148, 163, 184)',
        },
      },
      y: {
        display: true,
        grid: {
          color: 'rgba(71, 85, 105, 0.3)',
        },
        ticks: {
          color: 'rgb(148, 163, 184)',
          callback: function(value: any) {
            return '$' + value.toFixed(0) + 'B';
          },
        },
      },
    },
  };

  return (
    <div className={`${className}`}>
      <div className="flex justify-between items-center mb-4">
        <h3 className="text-lg font-semibold text-white">Market Capitalization Overview</h3>
        <div className="text-sm text-slate-400">
          Updated daily • Last update: {new Date().toLocaleDateString()}
        </div>
      </div>
      <div className="mb-4">
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-4">
          {data.slice(0, 8).map((item, index) => (
            <div 
              key={item.symbol} 
              className="bg-slate-700 p-3 rounded-lg text-center"
            >
              <div className="text-sm font-medium text-slate-200 mb-1">
                {item.symbol}
              </div>
              <div className="text-lg font-bold text-white mb-1">
                {formatMarketCap(item.marketCap)}
              </div>
              <div className={`text-sm ${
                item.change24h >= 0 ? 'text-green-400' : 'text-red-400'
              }`}>
                {item.change24h >= 0 ? '+' : ''}{item.change24h.toFixed(2)}%
              </div>
            </div>
          ))}
        </div>
      </div>
      <Bar data={chartData} options={options} />
    </div>
  );
};
